/**
 * bundleResolver.js
 * src/features/contracts/utils/bundleResolver.js
 *
 * SINGLE SOURCE OF TRUTH for all frontend bundle resolution.
 *
 * Previously duplicated between:
 *   - ContractBundleIntegration.jsx
 *   - ContractSettingsPage.jsx
 *   - bundleMatcher.js
 *
 * Import from here everywhere. Backend is the authoritative resolver —
 * this is for UI PREVIEW only (CreateOffer page, BundlePreviewBar, etc).
 * Real ContractInstances are generated by the backend in
 * moveToPendingCrewSignature().
 */

// ─── Categories ──────────────────────────────────────────────────────────────

export const CATEGORIES = [
  "Standard Crew",
  "Senior / Buyout",
  "Construction",
  "Electrical",
  "HOD",
  "Rigging",
  "Transport",
];

// categoryId values used in offer payload (match backend ContractFormCategory slugs)
export const CATEGORY_IDS = {
  "Standard Crew":  "standard_crew",
  "Senior / Buyout": "senior_buyout",
  "Construction":   "construction",
  "Electrical":     "electrical",
  "HOD":            "hod",
  "Rigging":        "rigging",
  "Transport":      "transport",
};

// ─── Engagement → Pay Family ─────────────────────────────────────────────────

/**
 * Maps offer.engagementType to the pay family used in bundle lookup.
 * Matches the backend ENGAGEMENT_MAP in contractInstance.service.js.
 */
export const ENGAGEMENT_TO_PAY_FAMILY = {
  paye:      "PAYE",
  loan_out:  "Loan Out",
  schd:      "Self Employed",   // Schedule D
  long_form: "PAYE",            // Direct hire — uses PAYE forms
};

export const ENGAGEMENT_LABELS = {
  paye:      "PAYE",
  loan_out:  "Loan Out",
  schd:      "Schedule D",
  long_form: "Direct Hire",
};

// ─── Allowance Forms (shared across all bundles) ──────────────────────────────

export const SHARED_ALLOWANCE_FORMS = [
  { key: "boxRental",          label: "Box Rental",           type: "allowance" },
  { key: "mobileAllowance",    label: "Mobile Allowance",     type: "allowance" },
  { key: "computerAllowance",  label: "Computer Allowance",   type: "allowance" },
];

// ─── Contract Forms per Pay Family ───────────────────────────────────────────

/**
 * Preview-only: shows which form types belong to each pay family.
 * Actual template HTML comes from ContractFormGroup in the database.
 */
export const BUNDLE_FORMS_MAP = {
  PAYE: [
    { key: "crew_information",       label: "Crew Information",          type: "contract",  required: true  },
    { key: "start_form",             label: "Start Form",                type: "contract",  required: true  },
    { key: "nda_confidentiality",    label: "NDA / Confidentiality",     type: "contract",  required: true  },
    { key: "policy_acknowledgement", label: "Policy Acknowledgement",    type: "contract",  required: true  },
    { key: "daily_paye",             label: "Daily PAYE Agreement",      type: "contract",  required: true  },
  ],
  "Self Employed": [
    { key: "crew_information",       label: "Crew Information",          type: "contract",  required: true  },
    { key: "start_form",             label: "Start Form",                type: "contract",  required: true  },
    { key: "nda_confidentiality",    label: "NDA / Confidentiality",     type: "contract",  required: true  },
    { key: "policy_acknowledgement", label: "Policy Acknowledgement",    type: "contract",  required: true  },
    { key: "lsa",                    label: "Labour Supply Agreement",   type: "contract",  required: true  },
  ],
  "Loan Out": [
    { key: "crew_information",       label: "Crew Information",          type: "contract",  required: true  },
    { key: "start_form",             label: "Start Form",                type: "contract",  required: true  },
    { key: "nda_confidentiality",    label: "NDA / Confidentiality",     type: "contract",  required: true  },
    { key: "policy_acknowledgement", label: "Policy Acknowledgement",    type: "contract",  required: true  },
    { key: "loan_out",               label: "Loan Out Agreement",        type: "contract",  required: true  },
  ],
};

// ─── Core Resolver ───────────────────────────────────────────────────────────

/**
 * Resolve a bundle preview from offer fields.
 *
 * @param {object} offer - Partial offer data (only needs 3 fields)
 * @param {string} offer.categoryId       - e.g. "standard_crew"
 * @param {string} offer.engagementType   - "paye" | "loan_out" | "schd" | "long_form"
 * @param {string} offer.dailyOrWeekly    - "daily" | "weekly"
 *
 * @returns {{
 *   bundleName:     string,
 *   tag:            string,
 *   contractForms:  Array,
 *   allowanceForms: Array,
 *   payFamily:      string,
 *   frequency:      string,
 *   categoryLabel:  string,
 * }}
 */
export function resolveContractBundle(offer) {
  const frequency = offer?.dailyOrWeekly === "weekly" ? "Weekly" : "Daily";

  const payFamily = ENGAGEMENT_TO_PAY_FAMILY[offer?.engagementType] || "PAYE";

  // Reverse-lookup category label from categoryId
  const categoryLabel =
    Object.entries(CATEGORY_IDS).find(([, id]) => id === offer?.categoryId)?.[0] ||
    offer?.categoryId ||
    "Standard Crew";

  const bundleName = `${frequency} ${payFamily} – ${categoryLabel}`;
  const tag        = `${frequency.toUpperCase()} ${payFamily.toUpperCase()}`;

  const contractForms  = BUNDLE_FORMS_MAP[payFamily] || BUNDLE_FORMS_MAP["PAYE"];
  const allowanceForms = SHARED_ALLOWANCE_FORMS;

  return {
    bundleName,
    tag,
    contractForms,
    allowanceForms,
    payFamily,
    frequency,
    categoryLabel,
  };
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * Returns true if the offer has all three fields needed for bundle resolution.
 * Use to decide whether to show BundlePreviewBar.
 */
export function canResolveBundle(offer) {
  return !!(offer?.categoryId && offer?.engagementType && offer?.dailyOrWeekly);
}

/**
 * Returns a short human-readable label for an engagement type.
 */
export function engagementLabel(engagementType) {
  return ENGAGEMENT_LABELS[engagementType] || engagementType;
}